<?php
namespace App\Http\Controllers;use App\Domain\Shops\Exceptions\ShopSaleConflictException;use App\Domain\Shops\Exceptions\ShopSaleSourceNotFoundException;use App\Domain\Shops\Exceptions\ShopSaleUnavailableException;use App\Domain\Shops\Exceptions\ShopSaleValidationException;use App\Domain\Shops\ShopSaleCommand;use App\Domain\Shops\ShopSaleService;use App\Http\Requests\SellShopItemRequest;use App\Models\Character;use App\Models\Shop;
final class ShopSaleController extends Controller{public function store(SellShopItemRequest $r,Character $character,Shop $shop,ShopSaleService $s){try{$result=$s->sell(new ShopSaleCommand($r->user(),$character,$shop,$r->validated()));return response()->json(['success'=>true,'message'=>'Venta realizada correctamente.','data'=>$result->toArray()],$result->replayed()?200:201);}catch(ShopSaleConflictException $e){return response()->json(['success'=>false,'message'=>'Conflicto de idempotencia.'],409);}catch(ShopSaleSourceNotFoundException $e){abort(404);}catch(ShopSaleUnavailableException $e){abort(404);}catch(ShopSaleValidationException $e){return response()->json(['success'=>false,'message'=>$e->getMessage()],422);}}}
